    about_label: "\u041f\u0440\u043e \u0433\u043e\u0442\u0435\u043b\u044c",
    about_title: "\u041f\u043e\u043d\u0430\u0434 \u0441\u0442\u043e \u0440\u043e\u043a\u0456\u0432 \u0456\u0441\u0442\u043e\u0440\u0456\u0457",
    about_text1: "\u0428\u0430\u043d\u043e\u0432\u043d\u0456 \u0413\u043e\u0441\u0442\u0456, \u043c\u0438 \u0449\u0438\u0440\u043e \u0437\u0430\u043f\u0440\u043e\u0448\u0443\u0454\u043c\u043e \u0412\u0430\u0441 \u0437\u0430\u0432\u0456\u0442\u0430\u0442\u0438 \u0434\u043e \u043d\u0430\u0448\u043e\u0433\u043e \u0433\u043e\u0442\u0435\u043b\u044e. \u0417\u0430 \u0434\u0432\u0430\u043d\u0430\u0434\u0446\u044f\u0442\u044c \u0440\u043e\u043a\u0456\u0432 \u0440\u043e\u0431\u043e\u0442\u0438 \u0440\u0435\u0441\u0442\u043e\u0440\u0430\u043d\u0443 \u043c\u0438 \u0437\u0456\u0431\u0440\u0430\u043b\u0438 \u0431\u0435\u0437\u043b\u0456\u0447 \u0432\u0456\u0434\u0433\u0443\u043a\u0456\u0432 \u043d\u0430\u0448\u0438\u0445 \u0433\u043e\u0441\u0442\u0435\u0439 \u2014 \u043f\u0440\u043e \u0442\u0435, \u0449\u043e \u0457\u043c \u043f\u043e\u0434\u043e\u0431\u0430\u0454\u0442\u044c\u0441\u044f, \u0430 \u0449\u043e \u043d\u0456 \u2014 \u0443 \u0433\u043e\u0442\u0435\u043b\u044f\u0445 \u043f\u043e \u0432\u0441\u044c\u043e\u043c\u0443 \u0441\u0432\u0456\u0442\u0443. \u0417\u0430\u0432\u0434\u044f\u043a\u0438 \u0446\u044c\u043e\u043c\u0443 \u043c\u0438 \u043d\u0430\u043c\u0430\u0433\u0430\u043b\u0438\u0441\u044f \u0441\u0442\u0432\u043e\u0440\u0438\u0442\u0438 \u043c\u0456\u0441\u0446\u0435, \u0434\u0435 \u0412\u0438 \u043f\u0440\u0438\u0454\u043c\u043d\u043e \u043f\u0440\u043e\u0432\u0435\u0434\u0435\u0442\u0435 \u0447\u0430\u0441. \u0406 \u043e\u0431\u043b\u0430\u0448\u0442\u0443\u0432\u0430\u043d\u043d\u044f \u043d\u043e\u043c\u0435\u0440\u0456\u0432, \u0456 \u043e\u0431\u0441\u043b\u0443\u0433\u043e\u0432\u0443\u0432\u0430\u043d\u043d\u044f \u043c\u0438 \u043d\u0430\u043c\u0430\u0433\u0430\u043b\u0438\u0441\u044f \u043f\u0456\u0434\u043f\u043e\u0440\u044f\u0434\u043a\u0443\u0432\u0430\u0442\u0438 \u0442\u0438\u043c \u0441\u0430\u043c\u0438\u043c \u043f\u0440\u0438\u043d\u0446\u0438\u043f\u0430\u043c, \u044f\u043a\u0438\u043c\u0438 \u0440\u043e\u043a\u0430\u043c\u0438 \u043a\u0435\u0440\u0443\u0454\u043c\u043e\u0441\u044f \u0443 \u0440\u0435\u0441\u0442\u043e\u0440\u0430\u043d\u0456.",
    about_text2: "\u041c\u0438 \u0445\u043e\u0442\u0456\u043b\u0438 \u0441\u0442\u0432\u043e\u0440\u0438\u0442\u0438 \u043c\u0456\u0441\u0446\u0435, \u0434\u0435 \u0412\u0438 \u0432\u0456\u0434\u0447\u0443\u0454\u0442\u0435 \u0441\u0435\u0431\u0435 \u044f\u043a \u0443\u0434\u043e\u043c\u0430. \u041d\u0430\u0448 \u0433\u043e\u0442\u0435\u043b\u044c \u0440\u043e\u0437\u0442\u0430\u0448\u043e\u0432\u0430\u043d\u043e \u0443 \u043f\u043e\u043d\u0430\u0434 \u0441\u0442\u043e\u043b\u0456\u0442\u043d\u0456\u0439 \u043a\u0430\u043c'\u044f\u043d\u0438\u0446\u0456, \u0430\u0440\u0445\u0456\u0442\u0435\u043a\u0442\u0443\u0440\u0430 \u044f\u043a\u043e\u0457 \u0434\u043e\u0437\u0432\u043e\u043b\u0438\u043b\u0430 \u043d\u0430\u043c \u0441\u0442\u0432\u043e\u0440\u0438\u0442\u0438 20 \u043d\u0435\u043f\u043e\u0432\u0442\u043e\u0440\u043d\u0438\u0445 \u043d\u043e\u043c\u0435\u0440\u0456\u0432. \u041a\u043e\u0436\u0435\u043d \u0437 \u043d\u0438\u0445 \u043e\u0431\u043b\u0430\u0434\u043d\u0430\u043d\u0438\u0439 \u0442\u0435\u043b\u0435\u0432\u0456\u0437\u043e\u0440\u043e\u043c, \u043c\u0456\u043d\u0456-\u0431\u0430\u0440\u043e\u043c, \u043a\u043e\u043d\u0434\u0438\u0446\u0456\u043e\u043d\u0435\u0440\u043e\u043c, \u0441\u0435\u0439\u0444\u043e\u043c \u0442\u0430 \u0456\u043d\u0442\u0435\u0440\u043d\u0435\u0442\u043e\u043c.",
