    rd_view_desc_full: "\u0414\u0432\u043e\u043c\u0456\u0441\u043d\u0438\u0439 \u043d\u043e\u043c\u0435\u0440 \u0456\u0437 \u043c\u0430\u043b\u044c\u043e\u0432\u043d\u0438\u0447\u0438\u043c \u0432\u0438\u0434\u043e\u043c \u043d\u0430 \u041e\u0434\u0440\u0443. \u041b\u0456\u0436\u043a\u043e \u043c\u043e\u0436\u043d\u0430 \u0440\u043e\u0437\u0434\u0456\u043b\u0438\u0442\u0438 \u043d\u0430 \u0434\u0432\u0430 \u043e\u0434\u043d\u043e\u0441\u043f\u0430\u043b\u044c\u043d\u0456 \u2014 \u0456\u0434\u0435\u0430\u043b\u044c\u043d\u0435 \u0440\u0456\u0448\u0435\u043d\u043d\u044f \u044f\u043a \u0434\u043b\u044f \u043f\u0430\u0440, \u0442\u0430\u043a \u0456 \u0434\u043b\u044f \u0434\u0440\u0443\u0437\u0456\u0432, \u0449\u043e \u043f\u043e\u0434\u043e\u0440\u043e\u0436\u0443\u044e\u0442\u044c \u0440\u0430\u0437\u043e\u043c. \u0417\u0440\u0443\u0447\u043d\u0430 \u0432\u0430\u043d\u043d\u0430 \u0437 \u0434\u0443\u0448\u0435\u043c, \u0440\u043e\u0431\u043e\u0447\u0438\u0439 \u0441\u0442\u0456\u043b \u0456 \u043f\u043e\u0432\u043d\u0435 \u043c\u0443\u043b\u044c\u0442\u0438\u043c\u0435\u0434\u0456\u0439\u043d\u0435 \u043e\u0431\u043b\u0430\u0434\u043d\u0430\u043d\u043d\u044f.",
    rd_mur_desc_full: "\u041e\u0434\u0438\u043d \u0456\u0437 \u0434\u0432\u043e\u0445 \u0443\u043d\u0456\u043a\u0430\u043b\u044c\u043d\u0438\u0445 \u0433\u043e\u0442\u0435\u043b\u044c\u043d\u0438\u0445 \u043d\u043e\u043c\u0435\u0440\u0456\u0432 \u0437 \u0432\u0456\u0434\u043a\u0440\u0438\u0442\u043e\u044e \u0456\u0441\u0442\u043e\u0440\u0438\u0447\u043d\u043e\u044e \u0444\u0430\u0445\u0432\u0435\u0440\u043a\u043e\u0432\u043e\u044e \u0441\u0442\u0456\u043d\u043e\u044e \u2014 \u043e\u0440\u0438\u0433\u0456\u043d\u0430\u043b\u044c\u043d\u0438\u043c \u043a\u043e\u043d\u0441\u0442\u0440\u0443\u043a\u0442\u0438\u0432\u043d\u0438\u043c \u0435\u043b\u0435\u043c\u0435\u043d\u0442\u043e\u043c \u0431\u0443\u0434\u0456\u0432\u043b\u0456. \u0414\u0435\u0440\u0435\u0432'\u044f\u043d\u0438\u0439 \u043a\u0430\u0440\u043a\u0430\u0441, \u0437\u0430\u043f\u043e\u0432\u043d\u0435\u043d\u0438\u0439 \u0446\u0435\u0433\u043b\u043e\u044e, \u043f\u043e\u0454\u0434\u043d\u0443\u0454\u0442\u044c\u0441\u044f \u0442\u0443\u0442 \u0456\u0437 \u0441\u0443\u0447\u0430\u0441\u043d\u0438\u043c \u0441\u043a\u043b\u0456\u043d\u043d\u044f\u043c \u0456 \u043a\u043e\u043c\u0444\u043e\u0440\u0442\u043d\u0438\u043c \u043e\u0431\u043b\u0430\u0434\u043d\u0430\u043d\u043d\u044f\u043c. \u0412\u0438\u0434 \u043d\u0430 \u0440\u0456\u0447\u043a\u0443 \u0437\u0430\u0432\u0435\u0440\u0448\u0443\u0454 \u043a\u0430\u0440\u0442\u0438\u043d\u0443. \u041d\u0435\u0437\u0440\u0456\u0432\u043d\u044f\u043d\u043d\u0435 \u043f\u043e\u0454\u0434\u043d\u0430\u043d\u043d\u044f \u0456\u0441\u0442\u043e\u0440\u0456\u0457 \u0442\u0430 \u0441\u0443\u0447\u0430\u0441\u043d\u043e\u0433\u043e \u0434\u0438\u0437\u0430\u0439\u043d\u0443.",
